        require(msg.value > 0, "Value cannot be zero");

        weiRaised += msg.value;
        tokensPurchased[beneficiary] += msg.value * rate;

        emit TokensPurchased(msg.sender, beneficiary, msg.value, msg.value * rate);

        wallet.transfer(msg.value);
    }
}
